import json, re
from collections import Counter

path = "data/output/benchmark/task_a/REDACTED.jsonl"
samples = [json.loads(l) for l in open(path)]

STATE_RE = re.compile(r"^\[STATE:\s*([A-Z0-9_]+)\s*(?:→|->)\s*([A-Z0-9_]+)\]")
TOOL_RE = re.compile(r"<tool_call>(.*?)</tool_call>", re.S)

issues = []
stats = Counter()
for s in samples:
    cid = s["conversation_id"]
    g = s["workflow_graph"]
    msgs = s["messages"]
    gt = s["ground_truth"]
    states = set(g["states"])
    valid_edges = {(t["from"], t["to"]) for t in g["transitions"]}
    stats[("domain", s["domain"])] += 1
    stats[("behavior", s["user_behavior"])] += 1
    stats[("lang", s["language"])] += 1
    stats[("init", s["conversation_initiator"])] += 1

    # graph sanity
    if g["initial"] not in states: issues.append((cid, "initial state not in states"))
    for t in g["transitions"]:
        if t["from"] not in states or t["to"] not in states:
            issues.append((cid, f"transition refs unknown state {t}"))
    for term in g["terminal"]:
        if term not in states: issues.append((cid, "terminal not in states"))

    # message roles
    if msgs[0]["role"] != "system": issues.append((cid, "first msg not system"))
    expected_first = "assistant" if s["conversation_initiator"] == "agent" else "user"
    if msgs[1]["role"] != expected_first:
        issues.append((cid, f"initiator={s['conversation_initiator']} but msgs[1].role={msgs[1]['role']}"))
    roles = [m["role"] for m in msgs[1:]]
    for a, b in zip(roles, roles[1:]):
        if a == b and a in ("user", "assistant"):
            issues.append((cid, f"consecutive {a} turns"))

    # state annotations
    ann = []
    for i, m in enumerate(msgs):
        if m["role"] == "assistant":
            mt = STATE_RE.match(m["content"])
            if not mt:
                issues.append((cid, f"assistant msg {i} missing [STATE] annotation"))
            else:
                ann.append((mt.group(1), mt.group(2)))
    # annotated transitions valid per graph
    for (a, b) in ann:
        if a not in states or b not in states:
            issues.append((cid, f"annotation uses unknown state {a}->{b}"))
        elif a != b and (a, b) not in valid_edges:
            issues.append((cid, f"annotated transition {a}->{b} not in graph"))
    # continuity
    for (p, q) in zip(ann, ann[1:]):
        if p[1] != q[0]:
            issues.append((cid, f"discontinuous annotations {p} then {q}"))
    if ann and ann[0][0] != g["initial"]:
        issues.append((cid, f"first annotation starts at {ann[0][0]}, initial={g['initial']}"))
    if ann and ann[-1][1] not in g["terminal"]:
        issues.append((cid, f"last annotation ends at {ann[-1][1]}, not terminal"))

    # ground truth vs annotations
    gt_seq = [(t["from"], t["to"]) for t in gt["state_sequence"]]
    if gt_seq != ann:
        issues.append((cid, f"ground_truth state_sequence != annotations: gt={gt_seq} ann={ann}"))
    if gt["terminal_state"] not in g["terminal"]:
        issues.append((cid, f"gt terminal {gt['terminal_state']} not in graph terminal"))

    # tool calls
    schema_names = {t["function"]["name"] if "function" in t else t.get("name") for t in s["tool_schemas"]}
    called = []
    for m in msgs:
        if m["role"] == "assistant":
            for raw in TOOL_RE.findall(m["content"]):
                try:
                    tc = json.loads(raw)
                    called.append(tc.get("name"))
                except json.JSONDecodeError:
                    issues.append((cid, "invalid JSON in <tool_call>"))
    for n in called:
        if n not in schema_names:
            issues.append((cid, f"tool call {n} not in schemas"))
    gt_tools = [t.get("name") for t in gt.get("tool_calls", [])]
    if called != gt_tools:
        issues.append((cid, f"tool calls in msgs {called} != gt {gt_tools}"))

print("=== distributions ===")
for k in ("domain", "behavior", "lang", "init"):
    print(k, dict((kk[1], v) for kk, v in stats.items() if kk[0] == k))
print(f"\n=== issues: {len(issues)} ===")
for cid, msg in issues[:60]:
    print(cid, "-", msg)
EOF

