    if re.search(r"\[Turn \d+\]|\[ตา \d+\]", text) or '"placeholder": "value"' in text:
        fp.append(s["conversation_id"])
print("placeholder fingerprints:", fp or "none")

STATE_RE = re.compile(r"^\[STATE:\s*([A-Z0-9_]+)\s*(?:→|->)\s*([A-Z0-9_]+)\]")
TOOL_RE = re.compile(r"<tool_call>(.*?)</tool_call>", re.S)
thai = re.compile(r"[฀-๿]")
issues = []
cons_tool = cons_prose = 0
tot = err = 0

for s in samples:
    cid = s["conversation_id"]
    g = s["workflow_graph"]
    msgs = s["messages"]
    gt = s["ground_truth"]
    states = set(g["states"])
    valid_edges = {(t["from"], t["to"]) for t in g["transitions"]}

    if msgs[0]["role"] != "system": issues.append((cid, "first msg not system"))
    expected_first = "assistant" if s["conversation_initiator"] == "agent" else "user"
    if msgs[1]["role"] != expected_first:
        issues.append((cid, f"initiator={s['conversation_initiator']} but msgs[1].role={msgs[1]['role']}"))
    for i in range(2, len(msgs)):
        if msgs[i]["role"] == "assistant" and msgs[i-1]["role"] == "assistant":
            body = re.sub(r"^\[STATE:[^\]]*\]\s*", "", msgs[i]["content"]).strip()
            if body.startswith("<tool_call>"): cons_tool += 1
            else: cons_prose += 1; issues.append((cid, "consecutive assistant prose turns"))
        if msgs[i]["role"] == "tool":
            tot += 1
            if '"error"' in msgs[i]["content"]: err += 1

    ann = []
    for i, m in enumerate(msgs):
        if m["role"] == "assistant":
            mt = STATE_RE.match(m["content"])
            if not mt: issues.append((cid, f"assistant msg {i} missing leading [STATE]"))
            else: ann.append((mt.group(1), mt.group(2)))
            extra = [x for x in re.finditer(r"\[STATE:", m["content"]) if x.start() != 0]
            if extra: issues.append((cid, f"msg {i}: mid-message [STATE:] marker"))
    for (a, b) in ann:
        if a not in states or b not in states: issues.append((cid, f"unknown state {a}->{b}"))
        elif a != b and (a, b) not in valid_edges: issues.append((cid, f"illegal edge {a}->{b}"))
    for p, q in zip(ann, ann[1:]):
        if p[1] != q[0]: issues.append((cid, f"discontinuous {p} then {q}"))
    if ann and ann[0][0] != g["initial"]: issues.append((cid, f"starts at {ann[0][0]} != initial"))
    if ann and ann[-1][1] not in g["terminal"]: issues.append((cid, f"ends at {ann[-1][1]}, not terminal"))

    gt_seq = [(t["from"], t["to"]) for t in gt["state_sequence"]]
    if gt_seq != ann: issues.append((cid, "gt state_sequence != message annotations"))

    schema_names = {t["function"]["name"] if "function" in t else t.get("name") for t in s["tool_schemas"]}
    state_tools = {d["name"]: set(d.get("tools", [])) for d in g["state_details"]}
    called = []
    for m in msgs:
        if m["role"] == "assistant":
            mt = STATE_RE.match(m["content"])
            cur = mt.group(1) if mt else None
            for raw in TOOL_RE.findall(m["content"]):
                try: tc = json.loads(raw)
                except json.JSONDecodeError: issues.append((cid, "invalid tool JSON")); continue
                called.append(tc.get("name"))
                if tc.get("name") not in schema_names: issues.append((cid, f"tool {tc.get('name')} not in schemas"))
                if cur and tc.get("name") not in state_tools.get(cur, set()):
                    issues.append((cid, f"tool {tc.get('name')} disallowed in {cur}"))
    gt_tools = [t.get("name") for t in gt.get("tool_calls", [])]
    if called != gt_tools: issues.append((cid, f"msg tools != gt"))

    # annotations field vs inline marker agreement
    for i, m in enumerate(msgs):
        if m["role"] == "assistant":
            mt = STATE_RE.match(m["content"])
            st = (m.get("annotations") or {}).get("state_transition") or {}
            if mt and st and (st.get("from"), st.get("to")) != (mt.group(1), mt.group(2)):
                issues.append((cid, f"msg {i}: annotations disagree with inline marker"))

    u = " ".join(m["content"] for m in msgs if m["role"] == "user")
    a = re.sub(r"\[STATE:[^\]]*\]|<tool_call>.*?</tool_call>", "", " ".join(m["content"] for m in msgs if m["role"] == "assistant"), flags=re.S)
    if (s["language"] == "th") != bool(thai.search(u)): issues.append((cid, f"user lang mismatch"))
    if s["language"] == "th" and len(a.strip()) > 40 and not thai.search(a): issues.append((cid, "assistant lang mismatch"))

print(f"tool responses: {tot}, errors: {err} ({err/max(tot,1):.0%})")
print(f"consecutive-assistant: speak→tool_call {cons_tool}, prose→prose {cons_prose}")
print(f"\nissues: {len(issues)}")
for cid, m in issues: print(" ", cid, "-", m)
